/* ── All data merged ────────────────────────────────────────────────────── */
const ALL_TICKERS = [...US_STOCKS, ...US_ETFS, ...KR_STOCKS, ...KR_ETFS, ...JP_STOCKS];

/* ── Region mapping ─────────────────────────────────────────────────────── */
type RegionFilter = "US" | "KR" | "JP" | "all";

function getRegionFilter(accountType: string | null): RegionFilter {
    switch (accountType) {
        case "US_DIRECT": return "US";
        case "ISA": return "KR";
        case "KR_DIRECT": return "KR";
        case "PENSION": return "KR";
        case "JP_DIRECT": return "JP";
        default: return "all";
    }
}

export async function GET(request: NextRequest) {
    const searchParams = request.nextUrl.searchParams;
    const query = searchParams.get("q")?.toLowerCase().trim() || "";
    const accountType = searchParams.get("account") || null;

    if (!query || query.length < 1) {
        return NextResponse.json({ results: [] });
    }

    const regionFilter = getRegionFilter(accountType);

    // 지역 필터 적용
    const pool = regionFilter === "all"
        ? ALL_TICKERS
        : ALL_TICKERS.filter(t => t.region === regionFilter);

    // 검색 점수 계산 (정확한 매치일수록 높은 점수)
    const scored = pool
        .map(ticker => {
            const sym = ticker.symbol.toLowerCase();
            const name = ticker.name.toLowerCase();
            let score = 0;

            if (sym === query) score = 100;
            else if (sym.startsWith(query)) score = 80;
            else if (sym.includes(query)) score = 60;
            else if (name.startsWith(query)) score = 50;
            else if (name.includes(query)) score = 30;
            else return null;

            return { ticker, score };
        })
        .filter(Boolean) as { ticker: TickerSearchResult; score: number }[];

    scored.sort((a, b) => b.score - a.score);

    // 중복 제거 (symbol + exchange 조합으로)
    const seen = new Set<string>();
    const uniqueResults: TickerSearchResult[] = [];
    for (const { ticker } of scored) {
        const key = `${ticker.symbol}-${ticker.exchange}`;
        if (!seen.has(key)) {
            seen.add(key);
            uniqueResults.push(ticker);
            if (uniqueResults.length >= 12) break;
        }
    }

    return NextResponse.json({ results: uniqueResults });
}
